import threading
import time
import random
import hashlib
import hmac
import secrets

class ATM:
    def __init__(self, atm_id, bank_server):
        self.atm_id = atm_id
        self.bank_server = bank_server
        self.lock = threading.Lock()  # Local lock for ATM operations
        self.session_key = None
        self.session_expiry = None

    def authenticate_user(self, card_number, pin):
        """Authenticates the user with the bank server and establishes a secure session."""
        try:
            response = self.bank_server.authenticate(self.atm_id, card_number, pin)
            if response['status'] == 'success':
                self.session_key = response['session_key']
                self.session_expiry = time.time() + 300  # Session expires in 5 minutes
                print(f"ATM {self.atm_id}: Authentication successful. Session key established.")
                return True
            else:
                print(f"ATM {self.atm_id}: Authentication failed: {response['message']}")
                return False
        except Exception as e:
            print(f"ATM {self.atm_id}: Authentication error: {e}")
            return False

    def _verify_session(self):
        """Verifies if the session is active and not expired."""
        if self.session_key is None or time.time() > self.session_expiry:
            print(f"ATM {self.atm_id}: Session expired or not established.")
            return False
        return True

    def check_balance(self, account_number):
        """Checks the account balance."""
        if not self._verify_session():
            return None

        try:
            data = {'account_number': account_number}
            signature = self._generate_signature(data)
            response = self.bank_server.get_balance(self.atm_id, self.session_key, data, signature)

            if response['status'] == 'success':
                print(f"ATM {self.atm_id}: Balance for account {account_number}: {response['balance']}")
                return response['balance']
            else:
                print(f"ATM {self.atm_id}: Balance check failed: {response['message']}")
                return None
        except Exception as e:
            print(f"ATM {self.atm_id}: Balance check error: {e}")
            return None

    def withdraw(self, account_number, amount):
        """Withdraws money from the account."""
        if not self._verify_session():
            return False

        with self.lock:  # Ensure only one transaction at a time
            try:
                data = {'account_number': account_number, 'amount': amount}
                signature = self._generate_signature(data)
                response = self.bank_server.withdraw(self.atm_id, self.session_key, data, signature)

                if response['status'] == 'success':
                    print(f"ATM {self.atm_id}: Withdrawal of {amount} from account {account_number} successful.")
                    return True
                else:
                    print(f"ATM {self.atm_id}: Withdrawal failed: {response['message']}")
                    return False
            except Exception as e:
                print(f"ATM {self.atm_id}: Withdrawal error: {e}")
                return False

    def deposit(self, account_number, amount):
        """Deposits money into the account."""
        if not self._verify_session():
            return False

        with self.lock:  # Ensure only one transaction at a time
            try:
                data = {'account_number': account_number, 'amount': amount}
                signature = self._generate_signature(data)
                response = self.bank_server.deposit(self.atm_id, self.session_key, data, signature)

                if response['status'] == 'success':
                    print(f"ATM {self.atm_id}: Deposit of {amount} to account {account_number} successful.")
                    return True
                else:
                    print(f"ATM {self.atm_id}: Deposit failed: {response['message']}")
                    return False
            except Exception as e:
                print(f"ATM {self.atm_id}: Deposit error: {e}")
                return False

    def _generate_signature(self, data):
        """Generates a HMAC signature for the data using the session key."""
        message = str(data).encode('utf-8')
        signature = hmac.new(self.session_key.encode('utf-8'), message, hashlib.sha256).hexdigest()
        return signature

    def end_session(self):
        """Ends the user session."""
        self.session_key = None
        self.session_expiry = None
        print(f"ATM {self.atm_id}: Session ended.")


