            self.session_expiry[atm_id] = time.time() + 300 # Session expires in 5 minutes
            return {"status": "success", "message": "Authentication successful", "session_key": session_key}
        else:
            return {"status": "error", "message": "Invalid card number or PIN"}

    def get_balance(self, atm_id, session_key, data, signature):
