        if account_number in self.accounts:
            return {"status": "success", "balance": self.accounts[account_number]["balance"]}
        else:
            return {"status": "error", "message": "Invalid account number"}

    def withdraw(self, atm_id, session_key, data, signature):
        """Withdraws money from the account."""
        if not self._verify_signature(atm_id, session_key, data, signature):
            return {"status": "error", "message": "Invalid signature"}

        account_number = data['account_number']
        amount = data['amount']

        if account_number in self.accounts:
            with self.account_locks[account_number]:  # Lock the account for concurrent access
                if self.accounts[account_number]["balance"] >= amount:
                    self.accounts[account_number]["balance"] -= amount
                    return {"status": "success", "message": "Withdrawal successful"}
                else:
                    return {"status": "error", "message": "Insufficient funds"}
        else:
            return {"status": "error", "message": "Invalid account number"}

    def deposit(self, atm_id, session_key, data, signature):
        """Deposits money into the account."""
        if not self._verify_signature(atm_id, session_key, data, signature):
            return {"status": "error", "message": "Invalid signature"}

        account_number = data['account_number']
        amount = data['amount']

        if account_number in self.accounts:
            with self.account_locks[account_number]:  # Lock the account for concurrent access
                self.accounts[account_number]["balance"] += amount
                return {"status": "success", "message": "Deposit successful"}
        else:
            return {"status": "error", "message": "Invalid account number"}

    def _verify_signature(self, atm_id, session_key, data, signature):
        """Verifies the HMAC signature."""
        if atm_id not in self.sessions or self.sessions[atm_id] != session_key or time.time() > self.session_expiry[atm_id]:
            print("Invalid or expired session")
            return False

        message = str(data).encode('utf-8')
        expected_signature = hmac.new(session_key.encode('utf-8'), message, hashlib.sha256).hexdigest()
        return hmac.compare_digest(signature, expected_signature)  # Prevent timing attacks

